import{_ as a,o as n,c as e,a2 as l}from"./chunks/framework.DH0WjybD.js";const h=JSON.parse('{"title":"ECharts 数据可视化","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/echarts.md","filePath":"knowledge/echarts.md","lastUpdated":null}'),o={name:"knowledge/echarts.md"};function p(r,s,t,c,i,E){return n(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="echarts-数据可视化" tabindex="-1">ECharts 数据可视化 <a class="header-anchor" href="#echarts-数据可视化" aria-label="Permalink to &quot;ECharts 数据可视化&quot;">​</a></h1><h2 id="知识简介" tabindex="-1">知识简介 <a class="header-anchor" href="#知识简介" aria-label="Permalink to &quot;知识简介&quot;">​</a></h2><p>ECharts 是百度开源的数据可视化图表库，提供折线图、柱状图、饼图、散点图、地图等丰富的图表类型。jinzhuan-project-web 项目使用 ECharts 5 实现数据可视化。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li><strong><code>echarts.init(dom)</code></strong>：初始化图表实例</li><li><strong><code>option</code></strong>：图表配置对象，定义图表类型、数据、样式</li><li><strong><code>series</code></strong>：图表系列，定义数据和图表类型</li><li><strong><code>xAxis</code> / <code>yAxis</code></strong>：坐标轴配置</li><li><strong><code>tooltip</code></strong>：提示框配置</li><li><strong><code>legend</code></strong>：图例配置</li><li><strong>响应式</strong>：<code>resize</code> 事件监听，自适应容器大小</li></ul><h2 id="详细讲解" tabindex="-1">详细讲解 <a class="header-anchor" href="#详细讲解" aria-label="Permalink to &quot;详细讲解&quot;">​</a></h2><p>在 jinzhuan-project-web 项目中，ECharts 作为依赖直接引入（<code>echarts: &quot;^5.5.0&quot;</code>），用于在仪表盘页面展示数据统计图表。</p><p>ECharts 的典型使用流程：</p><ol><li>准备 DOM 容器</li><li>初始化 ECharts 实例</li><li>配置 <code>option</code> 对象</li><li>调用 <code>setOption()</code> 渲染图表</li><li>监听 <code>resize</code> 事件实现自适应</li></ol><p>ECharts 在 Vite 中的优化配置：在 <code>package.json</code> 中配置 <code>optimizeDeps</code> 预构建 ECharts 相关模块：</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#9ECBFF;">&quot;echarts&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#9ECBFF;">&quot;echarts/charts&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#9ECBFF;">&quot;echarts/components&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#9ECBFF;">&quot;echarts/core&quot;</span><span style="color:#E1E4E8;">,</span></span>
<span class="line"><span style="color:#9ECBFF;">&quot;echarts/renderers&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="重点内容" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容" aria-label="Permalink to &quot;重点内容&quot;">​</a></h2><ul><li><code>setOption()</code> 可以增量更新（notMerge 参数控制是否合并）</li><li>ECharts 支持按需引入（减少打包体积）</li><li>常用图表类型：<code>line</code>、<code>bar</code>、<code>pie</code>、<code>scatter</code></li><li><code>tooltip</code> 支持自定义格式化内容</li><li>数据更新：再次调用 <code>setOption()</code> 即可</li></ul><h2 id="关键代码示例" tabindex="-1">关键代码示例 <a class="header-anchor" href="#关键代码示例" aria-label="Permalink to &quot;关键代码示例&quot;">​</a></h2><p>来源：<code>jinzhuan-project-web/src/components/Layout/layout.vue</code></p><p>ECharts 在项目的 vue3-count-to 插件中用于数字滚动效果，在仪表盘中展示统计数据。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">import</span><span style="color:#79B8FF;"> *</span><span style="color:#F97583;"> as</span><span style="color:#E1E4E8;"> echarts </span><span style="color:#F97583;">from</span><span style="color:#9ECBFF;"> &#39;echarts&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 初始化图表</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> chart</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> echarts.</span><span style="color:#B392F0;">init</span><span style="color:#E1E4E8;">(document.</span><span style="color:#B392F0;">getElementById</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;chart&#39;</span><span style="color:#E1E4E8;">))</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 配置图表</span></span>
<span class="line"><span style="color:#F97583;">const</span><span style="color:#79B8FF;"> option</span><span style="color:#F97583;"> =</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#E1E4E8;">  tooltip: { trigger: </span><span style="color:#9ECBFF;">&#39;axis&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">  legend: { data: [</span><span style="color:#9ECBFF;">&#39;数据A&#39;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&#39;数据B&#39;</span><span style="color:#E1E4E8;">] },</span></span>
<span class="line"><span style="color:#E1E4E8;">  xAxis: { type: </span><span style="color:#9ECBFF;">&#39;category&#39;</span><span style="color:#E1E4E8;">, data: [</span><span style="color:#9ECBFF;">&#39;周一&#39;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&#39;周二&#39;</span><span style="color:#E1E4E8;">, </span><span style="color:#9ECBFF;">&#39;周三&#39;</span><span style="color:#E1E4E8;">] },</span></span>
<span class="line"><span style="color:#E1E4E8;">  yAxis: { type: </span><span style="color:#9ECBFF;">&#39;value&#39;</span><span style="color:#E1E4E8;"> },</span></span>
<span class="line"><span style="color:#E1E4E8;">  series: [</span></span>
<span class="line"><span style="color:#E1E4E8;">    { name: </span><span style="color:#9ECBFF;">&#39;数据A&#39;</span><span style="color:#E1E4E8;">, type: </span><span style="color:#9ECBFF;">&#39;line&#39;</span><span style="color:#E1E4E8;">, data: [</span><span style="color:#79B8FF;">120</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">200</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">150</span><span style="color:#E1E4E8;">] },</span></span>
<span class="line"><span style="color:#E1E4E8;">    { name: </span><span style="color:#9ECBFF;">&#39;数据B&#39;</span><span style="color:#E1E4E8;">, type: </span><span style="color:#9ECBFF;">&#39;bar&#39;</span><span style="color:#E1E4E8;">, data: [</span><span style="color:#79B8FF;">80</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">120</span><span style="color:#E1E4E8;">, </span><span style="color:#79B8FF;">90</span><span style="color:#E1E4E8;">] }</span></span>
<span class="line"><span style="color:#E1E4E8;">  ]</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 渲染图表</span></span>
<span class="line"><span style="color:#E1E4E8;">chart.</span><span style="color:#B392F0;">setOption</span><span style="color:#E1E4E8;">(option)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 响应式自适应</span></span>
<span class="line"><span style="color:#E1E4E8;">window.</span><span style="color:#B392F0;">addEventListener</span><span style="color:#E1E4E8;">(</span><span style="color:#9ECBFF;">&#39;resize&#39;</span><span style="color:#E1E4E8;">, () </span><span style="color:#F97583;">=&gt;</span><span style="color:#E1E4E8;"> chart.</span><span style="color:#B392F0;">resize</span><span style="color:#E1E4E8;">())</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h2 id="实际应用场景" tabindex="-1">实际应用场景 <a class="header-anchor" href="#实际应用场景" aria-label="Permalink to &quot;实际应用场景&quot;">​</a></h2><ul><li>管理后台数据仪表盘</li><li>数据报表和统计图表</li><li>大数据可视化</li><li>实时数据监控</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>图表实例需要在组件销毁时调用 <code>dispose()</code> 释放资源</li><li>DOM 容器需要设置明确的宽高</li><li>数据更新时建议使用 <code>notMerge: true</code> 清空旧配置</li><li>在 Vue 中，建议使用 <code>ref</code> 获取 DOM 并用 <code>onMounted</code> 初始化图表</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>误区：忘记在组件卸载时销毁图表实例（内存泄漏）</li><li>误区：图表容器高度为 0 导致不显示</li><li>误区：频繁销毁重建图表（应使用 <code>setOption</code> 更新数据）</li></ul><h2 id="关联知识点" tabindex="-1">关联知识点 <a class="header-anchor" href="#关联知识点" aria-label="Permalink to &quot;关联知识点&quot;">​</a></h2><ul><li><a href="/frontend-knowledge-base/knowledge/vue3-composition-api.html">Vue 3 Composition API</a></li><li><a href="/frontend-knowledge-base/knowledge/dom-manipulation.html">DOM 操作</a></li></ul><h2 id="资料来源" tabindex="-1">资料来源 <a class="header-anchor" href="#资料来源" aria-label="Permalink to &quot;资料来源&quot;">​</a></h2><ul><li>来源项目：<code>新前端资源/jinzhuan-project-web/</code></li><li>来源文件：<code>package.json</code>（ECharts 依赖和预构建配置）</li><li>来源文件：<code>src/views/home/</code>（仪表盘页面）</li></ul><h2 id="官方资源扩展" tabindex="-1">官方资源扩展 <a class="header-anchor" href="#官方资源扩展" aria-label="Permalink to &quot;官方资源扩展&quot;">​</a></h2><ul><li><a href="https://echarts.apache.org/zh/index.html" target="_blank" rel="noreferrer">ECharts 官方文档</a></li><li>ECharts 官方文档，包含所有图表类型和配置项参考</li><li><a href="https://echarts.apache.org/examples/zh/index.html" target="_blank" rel="noreferrer">ECharts 示例库</a></li><li>官方示例库，可直接查看和修改图表代码</li></ul>`,29)])])}const u=a(o,[["render",p]]);export{h as __pageData,u as default};
